      "content": "const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', (req, res) => {
  const projectId = req.params.projectId;
  const status = req.query.status;
  const tasks = tasksService.getTasksByProject(projectId);
  if (!tasks) {
    return sendError(res, 404, 'NOT_FOUND', 'Project not found');
  }
  let filteredTasks = tasks;
  if (status) {
    filteredTasks = tasks.filter(task => task.status === status);
  }
  res.json({ tasks: filteredTasks });
});

router.post('/', (req, res) => {
  const projectId = req.params.projectId;
  const { title } = req.body;
  if (!title) {
    return sendError(res, 400, 'BAD_REQUEST', 'Title is required');
  }
  const task = tasksService.createTask(projectId, title);
  if (!task) {
    return sendError(res, 404, 'NOT_FOUND', 'Project not found');
  }
  res.status(201).json({ task });
});

router.patch('/:taskId', (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const { status } = req.body;
  if (!status || !['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'BAD_REQUEST', 'Invalid status');
  }
  const task = tasksService.updateTaskStatus(projectId, taskId, status);
  if (!task) {
    return sendError(res, 404, 'NOT_FOUND', 'Task not found');
  }
  res.json({ task });
});

module.exports = router;
