      "content": "const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');

let tasks = {};

function getTasksByProject(projectId) {
  const project = projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }
  return tasks[projectId] || [];
}

function createTask(projectId, title) {
  const project = projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }
  const taskId = randomUUID();
  const task = { id: taskId, title, status: 'todo' };
  if (!tasks[projectId]) {
    tasks[projectId] = [];
  }
  tasks[projectId].push(task);
  return task;
}

function updateTaskStatus(projectId, taskId, status) {
  const projectTasks = getTasksByProject(projectId);
  if (!projectTasks) {
    return null;
  }
  const taskIndex = projectTasks.findIndex(task => task.id === taskId);
  if (taskIndex === -1) {
    return null;
  }
  projectTasks[taskIndex].status = status;
  return projectTasks[taskIndex];
}

module.exports = {
  getTasksByProject,
  createTask,
  updateTaskStatus,
};
